// LESSON: JavaFX Layout and Data - Reference Page 2.
// You will learn: Bind ObservableList data to controls and update selection state.
import javafx.application.Application;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.ListView;
import javafx.scene.control.TextField;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.HBox;
import javafx.stage.Stage;

public class JavaFxLayoutDataReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    // EXAMPLE 1: connect ObservableList to ListView.
    ObservableList<String> data = FXCollections.observableArrayList();
    data.add("First row");
    ListView<String> listView = new ListView<>(data);
    // EXAMPLE 2: add data from a text field.
    TextField input = new TextField();
    Button addButton = new Button("Add");
    addButton.setOnAction(event -> {
      String text = input.getText().trim();
      if (!text.isEmpty()) {
        data.add(text);
        input.clear();
      }
    });
    // EXAMPLE 3: combine selection, HBox, and BorderPane.
    Label selectedLabel = new Label("Choose a row");
    listView.getSelectionModel().selectedItemProperty().addListener((obs, oldValue, newValue) -> {
      selectedLabel.setText(newValue == null ? "Choose a row" : "Selected: " + newValue);
    });
    BorderPane root = new BorderPane(listView);
    root.setTop(selectedLabel);
    root.setBottom(new HBox(5, input, addButton));
    stage.setScene(new Scene(root, 360, 240));
    stage.show();
  }
}
